import{_ as l,C as p,o as a,c as d,a5 as o,b as s,w as t,a as r,E as c,a6 as h,j as i}from"./chunks/framework.CMvIMz6I.js";const w=JSON.parse('{"title":"Security architecture","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/security/index.md","filePath":"concepts/security/index.md"}'),u={name:"concepts/security/index.md"};function m(f,e,g,y,v,A){const n=p("Mermaid");return a(),d("div",null,[e[2]||(e[2]=o('<h1 id="security-architecture" tabindex="-1">Security architecture <a class="header-anchor" href="#security-architecture" aria-label="Permalink to &quot;Security architecture&quot;">​</a></h1><p>Securing a distributed, multi-tenant platform that spans organizational boundaries requires a deliberate architectural approach. Traditional monolithic security models, where authentication and authorization are tightly coupled within a single system, fail to address the dynamic nature of service ecosystems where <a href="/pr-preview/pr-152/concepts/personas/service-provider.html">service providers</a>, <a href="/pr-preview/pr-152/concepts/personas/service-consumer.html">service consumers</a>, and marketplace operators interact across isolated <a href="/pr-preview/pr-152/concepts/control-planes.html">control planes</a>.</p><p>Platform Mesh addresses this challenge through a clear separation of authentication and authorization as independent architectural concerns, each implemented by purpose-built components that can evolve, scale, and be replaced independently. This design aligns directly with the <a href="/pr-preview/pr-152/concepts/why-platform-mesh.html">decoupling principle</a> that guides the overall architecture: security subsystems, like all other components, should be directly usable without requiring the complete framework.</p><p>For the runtime view — which component plays which role and how requests pass through the authorizer chain — see <a href="/pr-preview/pr-152/concepts/identity-and-authorization.html">Identity and authorization</a>.</p><h2 id="client-entry-paths" tabindex="-1">Client entry paths <a class="header-anchor" href="#client-entry-paths" aria-label="Permalink to &quot;Client entry paths&quot;">​</a></h2><p>Platform Mesh is accessed through multiple client types, each with distinct interaction patterns. UI clients interact through a Kubernetes-GraphQL-Gateway, <code>kubectl</code> users communicate directly with <a href="https://kcp.io" target="_blank" rel="noreferrer">kcp</a> via the KRM API, and AI agents are expected to interact through a dedicated MCP (Model Context Protocol) server<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup>. Regardless of the client type, all requests ultimately reach kcp, where the same authentication and authorization mechanisms apply uniformly.</p>',6)),(a(),s(h,null,{default:t(()=>[c(n,{id:"mermaid-18",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20UI%5BUI%20Client%5D%20--%3E%20GW%5BGraphQL%20Gateway%5D%0A%20%20%20%20CLI%5Bkubectl%5D%20--%3E%20KCP%0A%20%20%20%20GW%20--%3E%20KCP%5Bkcp%5D%0A%20%20%20%20AI%5BAI%20Client%5D%20-.-%3E%20MCP%5B%22MCP%20Server%20(planned)%22%5D%0A%20%20%20%20MCP%20-.-%3E%20KCP%0A%0A%20%20%20%20style%20MCP%20stroke-dasharray%3A%205%205%0A%20%20%20%20style%20AI%20stroke-dasharray%3A%205%205%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[r(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=i("h2",{id:"authentication-and-authorization-flow",tabindex:"-1"},[r("Authentication and authorization flow "),i("a",{class:"header-anchor",href:"#authentication-and-authorization-flow","aria-label":'Permalink to "Authentication and authorization flow"'},"​")],-1)),e[4]||(e[4]=i("p",null,"Once a request reaches kcp, the authentication configuration establishes the caller's identity, and a layered authorizer chain decides whether the request is allowed. RBAC handles structural, resource-type access; the authorization webhook forwards anything RBAC has no opinion on to OpenFGA for relationship-based evaluation.",-1)),(a(),s(h,null,{default:t(()=>[c(n,{id:"mermaid-25",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20KCP%5Bkcp%5D%20--%3E%20AUTHN%5BAuthN%20Config%5D%0A%20%20%20%20AUTHN%20--%3E%7COIDC%7C%20KC%5BKeycloak%5D%0A%20%20%20%20AUTHN%20--%3E%20SA%5BServiceAccounts%5D%0A%20%20%20%20KC%20--%3E%7Cidentity%20established%7C%20RBAC%5BRBAC%5D%0A%20%20%20%20SA%20--%3E%7Cidentity%20established%7C%20RBAC%0A%20%20%20%20RBAC%20--%3E%7Cgranted%7C%20RES%5BAccess%20Granted%5D%0A%20%20%20%20RBAC%20--%3E%7Cdenied%7C%20DENY%5BAccess%20Denied%5D%0A%20%20%20%20RBAC%20--%3E%7Cno%20opinion%7C%20WH%5BAuthZ%20Webhook%5D%0A%20%20%20%20WH%20--%3E%7Ccheck%7C%20FGA%5BOpenFGA%5D%0A%20%20%20%20FGA%20--%3E%7Cgranted%7C%20RES%0A%20%20%20%20FGA%20--%3E%7Cdenied%7C%20DENY%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[r(" Loading... ",-1)])]),_:1})),e[5]||(e[5]=o('<h2 id="separation-of-concerns" tabindex="-1">Separation of concerns <a class="header-anchor" href="#separation-of-concerns" aria-label="Permalink to &quot;Separation of concerns&quot;">​</a></h2><p><a href="./authentication.html">Authentication</a> and <a href="./authorization.html">authorization</a> are independent subsystems, reflecting Platform Mesh <a href="/pr-preview/pr-152/concepts/why-platform-mesh.html">guiding principles</a>. The two are connected solely through the OIDC token: authentication produces it, authorization consumes the identity claims within it. While OIDC tokens carry claims such as group memberships that inform RBAC decisions, the token should establish <em>who</em> the caller is, not <em>what</em> they are allowed to do — encoding permissions as group claims is an anti-pattern that blurs this boundary. They share no other state, meaning each can evolve, scale, and be replaced independently. Both are integrated through standard Kubernetes extension points (authentication configurations for identity providers and authorization webhooks for authorizers), enabling alternative implementations that satisfy the same interfaces.</p><p>However, Platform Mesh provides specific integration with Keycloak and OpenFGA, such as per-organization realm and store provisioning, identity brokering configuration, and dynamic authorization schema generation. Replacing either component with an alternative would require reimplementing these integration aspects.</p><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>Platform Mesh security architecture represents ongoing research in distributed authorization patterns. The model continues to evolve to support enhanced cross-provider authorization scenarios, relationship-based authorization model management, and advanced authorization propagation across the account hierarchy.</p></div><p>Platform Mesh security architecture builds on <a href="https://kcp.io" target="_blank" rel="noreferrer">kcp</a>&#39;s own security foundations, including workspace isolation, APIExport identity, and permission claims. For a detailed analysis of these foundations, see the <a href="https://docs.kcp.io/kcp/v0.30/contributing/governance/security-self-assessment/" target="_blank" rel="noreferrer">kcp Security Self-Assessment</a> (particularly the <a href="https://docs.kcp.io/kcp/v0.30/contributing/governance/security-self-assessment/#security-functions-and-features" target="_blank" rel="noreferrer">Security Functions and Features</a> section) and the <a href="https://docs.kcp.io/kcp/v0.30/contributing/governance/general-technical-review/#security" target="_blank" rel="noreferrer">security section of kcp&#39;s General Technical Review</a>.</p><h2 id="security-and-the-account-model" tabindex="-1">Security and the account model <a class="header-anchor" href="#security-and-the-account-model" aria-label="Permalink to &quot;Security and the account model&quot;">​</a></h2><p>The security architecture integrates deeply with the Platform Mesh <a href="/pr-preview/pr-152/concepts/account-model.html">account model</a>, ensuring that security boundaries align with organizational boundaries throughout the hierarchy.</p><ul><li><strong>Per-organization identity realm:</strong> Platform Mesh creates a dedicated Keycloak realm for each organization, providing complete isolation of user stores, client configurations, and authentication policies. This realm is configured as an OIDC provider through <a href="https://kcp.io" target="_blank" rel="noreferrer">kcp</a>&#39;s authentication configuration, tying the organization&#39;s identity management directly to its account hierarchy.</li><li><strong>Per-organization FGA store:</strong> Similarly, each organization receives a dedicated OpenFGA store, isolating authorization state across organizational boundaries. This ensures that relationship tuples and authorization evaluations for one organization cannot interfere with another.</li><li><strong>Dynamic authorization schema:</strong> Platform Mesh dynamically generates the OpenFGA authorization schema for each organization based on the APIs bound within that organization&#39;s accounts. As <a href="/pr-preview/pr-152/concepts/personas/service-provider.html">service providers</a> expose new capabilities and consumers bind to them, the authorization model automatically evolves to include the corresponding types and relations, eliminating the need for manual schema maintenance.</li><li><strong>Hierarchical inheritance:</strong> OpenFGA relationship tuples can be inherited through the account hierarchy. Permissions defined at a parent account can propagate to child accounts through the relationship graph, simplifying governance while allowing overrides where organizational requirements demand it.</li><li><strong>Service-relationship authorization:</strong> When <a href="/pr-preview/pr-152/concepts/personas/service-consumer.html">service consumers</a> engage with <a href="/pr-preview/pr-152/concepts/personas/service-provider.html">service providers</a> through the export and bind mechanisms of the account model, the authorization layer automatically reflects these relationships. OpenFGA also controls where in the account hierarchy a provider&#39;s service can be bound, ensuring that service consumption is constrained to the appropriate organizational scope.</li><li><strong>Marketplace integration:</strong> When a provider API is activated through a <a href="/pr-preview/pr-152/reference/components/marketplace.html">marketplace</a>, the OpenFGA authorization schema for the organization is extended to include the corresponding resource types and relations, making the new service&#39;s resources available for fine-grained authorization decisions.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./authentication.html">Authentication</a> — design view of how identity is established</li><li><a href="./authorization.html">Authorization</a> — design view of layered RBAC + ReBAC decisions</li><li><a href="/pr-preview/pr-152/concepts/identity-and-authorization.html">Identity and authorization</a> — runtime view of the same components</li><li><a href="/pr-preview/pr-152/concepts/account-model.html">Account model</a> — organizational hierarchy that frames per-org isolation</li><li><a href="/pr-preview/pr-152/reference/components/keycloak.html">Keycloak</a> — reference for the identity provider component</li><li><a href="/pr-preview/pr-152/reference/components/openfga.html">OpenFGA</a> — reference for the authorization engine component</li><li><a href="/pr-preview/pr-152/reference/components/rebac-authz-webhook.html">rebac-authz-webhook</a> — reference for the kcp ↔ OpenFGA bridge</li></ul><hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="fn1" class="footnote-item"><p>The MCP server for Platform Mesh is a planned future component. <a href="#fnref1" class="footnote-backref">↩︎</a></p></li></ol></section>',12))])}const k=l(u,[["render",m]]);export{w as __pageData,k as default};
